22	    const key = cellKey(neighbor);
23	    const entry = tally.get(key) ?? { cell: neighbor, count: 0 };
24	    entry.count++;
25	    tally.set(key, entry);
26	  }
27	  return tally;
28	};
29	
30	const isAliveNextGen = (count: number, wasAlive: boolean): boolean =>
31	  count === BIRTH_NEIGHBORS || (count === SURVIVAL_NEIGHBORS && wasAlive);
32	
33	export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
34	  const isAlive = new Set(liveCells.map(cellKey));
35	  return [...tallyNeighbors(liveCells)]
36	    .filter(([key, { count }]) => isAliveNextGen(count, isAlive.has(key)))
37	    .map(([, { cell }]) => cell);
38	}
